const jobData = $input.item.json;
const { execSync } = require('child_process');
const dbPath = '/home/n8n/.n8n/job_search.db';

function sqlExec(sql) {
  try {
    execSync('sqlite3 ' + dbPath, { input: sql, timeout: 10000 });
  } catch(e) {
    console.error('SQLite error:', e.message);
  }
}

function escapeSql(s) {
  return String(s || '').replace(/'/g, "''");
}

sqlExec('CREATE TABLE IF NOT EXISTS applications (id TEXT PRIMARY KEY, company_name TEXT, job_title TEXT, location TEXT, job_url TEXT, job_description TEXT, applied_date TEXT, status TEXT DEFAULT \'applied\', folder_path TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);');

sqlExec('CREATE TABLE IF NOT EXISTS tier_outputs (id INTEGER PRIMARY KEY AUTOINCREMENT, application_id TEXT, tier_name TEXT, status TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);');

sqlExec('CREATE TABLE IF NOT EXISTS follow_ups (id INTEGER PRIMARY KEY AUTOINCREMENT, application_id TEXT, due_date TEXT, type TEXT, status TEXT DEFAULT \'pending\', created_at TEXT DEFAULT CURRENT_TIMESTAMP);');

sqlExec('CREATE TABLE IF NOT EXISTS analytics (id TEXT PRIMARY KEY, metric_name TEXT, metric_value INTEGER, last_updated TEXT);');

sqlExec('INSERT OR REPLACE INTO applications (id, company_name, job_title, location, job_url, job_description, applied_date, status, folder_path) VALUES (\'' + escapeSql(jobData.application_id) + '\', \'' + escapeSql(jobData.company_name) + '\', \'' + escapeSql(jobData.job_title) + '\', \'' + escapeSql(jobData.location) + '\', \'' + escapeSql(jobData.job_url) + '\', \'' + escapeSql(jobData.job_description) + '\', \'' + escapeSql(jobData.applied_date) + '\', \'applied\', \'' + escapeSql(jobData.folder_path) + '\');');

const tiers = ['tier1', 'tier2', 'tier3', 'tier4', 'tier5'];
