const jobData = $input.item.json;

function extractKeywords(text) {
  if (!text) return [];
  const pattern = /\b(React|Angular|Vue|Node\.js|Python|Java|TypeScript|JavaScript|AWS|GCP|Azure|Docker|Kubernetes|PostgreSQL|MySQL|MongoDB|Redis|GraphQL|REST|API|CI\/CD|Git|Agile|Scrum|Terraform|Ansible|Jenkins|Linux|Bash|Go|Rust|C\+\+|C#|\.NET|Spring|FastAPI|Django|Flask|Microservices|Serverless|Machine Learning|Deep Learning|NLP|Data Science|Spark|Kafka|Elasticsearch|Kibana|Prometheus|Grafana|ArgoCD|Helm|RabbitMQ|gRPC|OAuth|JWT|SAML|RBAC|TDD|BDD|DDD|CQRS|Event Sourcing|Distributed Systems|System Design|Architecture)\b/gi;
  const matches = text.match(pattern) || [];
  const seen = {};
  const unique = [];
  for (const m of matches) {
    const lower = m.toLowerCase();
    if (!seen[lower]) {
      seen[lower] = true;
      unique.push(lower);
    }
  }
  return unique;
}

const jobText = (jobData.job_description || '') + ' ' + (jobData.job_requirements || '');
const jobKeywords = extractKeywords(jobText);
const userKeywords = extractKeywords(jobData.user_skills || '');
const resumeKeywords = extractKeywords(jobData.resume_content || '');

const allCoveredKeywords = {};
for (const k of userKeywords) allCoveredKeywords[k] = true;
for (const k of resumeKeywords) allCoveredKeywords[k] = true;

const matching = jobKeywords.filter(function(k) { return allCoveredKeywords[k]; });
const missing = jobKeywords.filter(function(k) { return !allCoveredKeywords[k]; });

const atsScore = jobKeywords.length > 0 ? Math.round((matching.length / jobKeywords.length) * 100) : 0;

let recommendation = '';
if (atsScore >= 70) {
  recommendation = 'Strong ATS match (' + atsScore + '%). Proceed with application.';
} else if (atsScore >= 50) {
  recommendation = 'Moderate ATS match (' + atsScore + '%). Consider weaving missing keywords into resume.';
} else {
  recommendation = 'Low ATS match (' + atsScore + '%). Update resume with missing keywords before applying.';
}

const atsReport = '# ATS Keyword Optimization Report\n\n' +
  '**ATS Score: ' + atsScore + '%**\n\n' +
  '## Matched Keywords (' + matching.length + ')\n' +
  (matching.length ? matching.map(function(k) { return '- ' + k; }).join('\n') : '- None found') + '\n\n' +
  '## Missing Keywords (' + missing.length + ')\n' +
  (missing.length ? missing.map(function(k) { return '- ' + k; }).join('\n') : '- None missing') + '\n\n' +
  '## Recommendation\n' + recommendation + '\n';

return [{
  json: {
    ...jobData,
    ats_keywords_matched: matching,
    ats_keywords_missing: missing,
    ats_score: atsScore,
    ats_report: atsReport
  }
}];

const jobData = $input.item.json;
const githubToken = process.env.GITHUB_TOKEN || '';

if (!githubToken) {
  console.log('Warning: GITHUB_TOKEN not set, skipping git commit');
  return [{
    json: {
      ...jobData,
      git_status: 'skipped'
    }
  }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const apiBase = 'https://api.github.com';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  return await $helpers.httpRequest({
    method: method,
    url: apiBase + path,
    headers: headers,
    body: body,
  });
}

try {
  const refData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/git/refs/heads/main');
  const currentSha = refData.object.sha;

  const commitData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/git/commits/' + currentSha);
  const treeSha = commitData.tree.sha;

  const filesToCommit = [];

  const contentMap = {
    'metadata.md': jobData.metadata_content,
    'resume.md': jobData.resume_content,
    'cover_letter.md': jobData.cover_letter_content,
    'cold_email.md': jobData.cold_email_content,
    'company_research.md': jobData.company_research_content,
    'personal_angle.md': jobData.personal_angle_content,
    'interview_prep.md': jobData.interview_prep_content,
    'portfolio_matching.md': jobData.portfolio_content,
    'tracking.md': jobData.tracking_content,
    'ats_report.md': jobData.ats_report
  };

  for (const [fileName, content] of Object.entries(contentMap)) {
    if (!content) {
      console.log('Skipping ' + fileName + ': no content available');
      continue;
    }
    try {
      const blobData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/blobs', {
        content: Buffer.from(content).toString('base64'),
        encoding: 'base64'
      });
      const repoPath = jobData.year + '/' + jobData.month + '/' + jobData.folder_name + '/' + fileName;
      filesToCommit.push({ path: repoPath, mode: '100644', type: 'blob', sha: blobData.sha });
    } catch(e) {
      console.error('Error processing file ' + fileName + ':', e.message);
    }
  }

  if (jobData.analytics_content) {
    try {
      const analyticsBlobData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/blobs', {
        content: Buffer.from(jobData.analytics_content).toString('base64'),
        encoding: 'base64'
      });
      filesToCommit.push({ path: 'analytics.md', mode: '100644', type: 'blob', sha: analyticsBlobData.sha });
    } catch(e) {
      console.error('Error processing analytics.md:', e.message);
    }
  }

  if (filesToCommit.length === 0) {
    return [{
      json: {
        ...jobData,
        git_status: 'skipped',
        git_note: 'No content to commit'
      }
    }];
  }

  const newTreeData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/trees', {
    base_tree: treeSha,
    tree: filesToCommit
  });
  const newTreeSha = newTreeData.sha;

  const commitMessage = 'Job application: ' + jobData.company_name + ' - ' + jobData.job_title + ' - ' + jobData.applied_date;
  const newCommitData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/commits', {
    message: commitMessage,
    tree: newTreeSha,
    parents: [currentSha],
    author: {
      name: 'Odeliya Charitonova',
      email: 'odaliya12@gmail.com',
      date: new Date().toISOString()
    }
  });
  const newCommitSha = newCommitData.sha;

  await apiRequest('PATCH', '/repos/' + owner + '/' + repo + '/git/refs/heads/main', {
    sha: newCommitSha,
    force: false
  });

  return [{
    json: {
      ...jobData,
      git_status: 'success',
      commit_sha: newCommitSha
    }
  }];

} catch(e) {
  console.error('Git commit failed:', e.message);
  return [{
    json: {
      ...jobData,
      git_status: 'error',
      git_error: e.message
    }
  }];
}
